```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a read-only adaptor over the span and a binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet{};

    // 1. Read the packet_id
    stream >> packet.packet_id;

    // 2. Read the username using a length prefix.
    //    We first read the length, then read that many bytes into a string.
    uint32_t username_len{};
    stream >> username_len;
    if (username_len > 0) {
        std::string tmp(username_len, '\0');
        stream.read(tmp.data(), username_len);
        packet.username = std::move(tmp);
    } else {
        packet.username.clear();
    }

    // 3. Read score count, then use read_container to fill scores vector
    uint32_t score_count{};
    stream >> score_count;
    packet.scores.resize(score_count);
    stream.read_container(packet.scores);

    // 4. Read metadata string as null-terminated, using zero-copy where possible.
    //    We use span() to get a view into remaining bytes, then scan for '\0'.
    {
        auto remaining_span = stream.span<std::uint8_t>(
            adaptor.size() - stream.tell()
        );

        const auto* begin = remaining_span.data();
        const auto* end   = remaining_span.data() + remaining_span.size();
        const auto* nul   = static_cast<const std::uint8_t*>(
            std::memchr(begin, '\0', static_cast<size_t>(end - begin))
        );

        if (nul == nullptr) {
            // No null terminator; treat all remaining bytes as metadata
            packet.metadata.assign(reinterpret_cast<const char*>(begin),
                                   static_cast<std::size_t>(end - begin));
            stream.skip(end - begin);
        } else {
            // Metadata up to (but not including) the null terminator
            auto meta_len = static_cast<std::size_t>(nul - begin);
            packet.metadata.assign(reinterpret_cast<const char*>(begin),
                                   meta_len);

            // Advance past metadata + null terminator
            stream.skip(meta_len + 1);
        }
    }

    // 5. Skip any remaining padding bytes (if any)
    auto remaining = adaptor.size() - stream.tell();
    if (remaining > 0) {
        stream.skip(remaining);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketInfo info{};

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    {
        auto id_span = stream.span<std::uint8_t>(sizeof(uint32_t));
        info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());
        stream.skip(sizeof(uint32_t));
    }

    // 2. Read username using a length-prefixed adaptor to get a string_view
    uint32_t username_len{};
    stream >> username_len;

    std::string_view username_view;
    if (username_len > 0) {
        auto name_span = stream.span<char>(username_len);
        username_view = std::string_view(name_span.data(), username_len);
        stream.skip(username_len);
    } else {
        username_view = std::string_view{};
    }
    info.username = username_view;

    // 3. Skip the scores vector without reading its elements
    //    - read count, then skip count * sizeof(uint32_t) bytes
    uint32_t score_count{};
    stream >> score_count;
    std::size_t scores_bytes = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    if (scores_bytes > 0) {
        stream.skip(scores_bytes);
    }

    return info;
}
