#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Wrap the incoming span in a Hexi buffer adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Get a zero-copy span over the header bytes
    auto header_span = stream.span<std::uint8_t>(sizeof(PacketHeader));

    PacketHeader header{};
    header.version   = header_span[0];
    header.flags     = header_span[1];

    // Assuming native endianness for packet_id; adjust if protocol specifies otherwise.
    header.packet_id = static_cast<std::uint16_t>(
        static_cast<std::uint16_t>(header_span[2]) |
        (static_cast<std::uint16_t>(header_span[3]) << 8)
    );

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Obtain a zero-copy view until a null terminator (0) is found.
    auto msg_view = stream.view<char>('\0');

    // Hexi's view likely excludes the delimiter; we return the view directly.
    return msg_view;
}
