```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a read-only adaptor over the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Determine how many bytes we can actually peek
    const auto available = adaptor.size();
    const auto to_copy   = std::min<std::size_t>(bytes_to_peek, available);

    // Prepare destination vector
    std::vector<uint8_t> out(to_copy);

    // Copy without advancing the read position
    adaptor.copy(out.data(), to_copy);

    return out;
}
```

