#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, GetReadPointer) {
    std::vector<uint8_t> buffer = {1, 2, 3, 4, 5};

    const uint8_t* ptr = get_read_pointer(buffer);

    ASSERT_NE(nullptr, ptr);
    EXPECT_EQ(1, *ptr);
}

TEST(BufferAdaptor, GetWritePointer) {
    std::vector<uint8_t> buffer(10, 0);

    uint8_t* ptr = get_write_pointer(buffer);

    ASSERT_NE(nullptr, ptr);
}

TEST(BufferAdaptor, CheckBufferSpace) {
    std::vector<uint8_t> buffer = {1, 2, 3};

    BufferInfo info = check_buffer_space(buffer);

    EXPECT_EQ(3, info.readable_size);
    EXPECT_GE(info.free_space, 0);
}

TEST(BufferAdaptor, CheckEmptyBuffer) {
    std::vector<uint8_t> buffer;

    BufferInfo info = check_buffer_space(buffer);

    EXPECT_EQ(0, info.readable_size);
}

