const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Use Hexi's buffer_adaptor to get the current read position.
    // For a freshly-constructed adaptor over a std::vector, the read
    // pointer is at the start of the underlying storage.
    hexi::buffer_adaptor adaptor(buffer);

    // If the buffer is empty, return nullptr to indicate no readable data.
    if (buffer.empty()) {
        return nullptr;
    }

    // buffer_adaptor works over contiguous storage; &buffer[0] is valid here.
    return buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Use Hexi's buffer_adaptor to determine the current write position.
    hexi::buffer_adaptor adaptor(buffer);

    // The write position in this simple adaptor setup is at
    // buffer.data() + adaptor.size(), where size() is the readable size.
    std::size_t write_offset = adaptor.size();

    // Ensure the vector is large enough to accommodate writes at that offset.
    // If the vector is smaller than write_offset, resize it up to that point.
    if (buffer.size() < write_offset) {
        buffer.resize(write_offset);
    }

    return buffer.data() + write_offset;
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Wrap the vector in a Hexi buffer_adaptor to query size information.
    hexi::buffer_adaptor adaptor(buffer);

    BufferInfo info{};
    info.readable_size = adaptor.size();

    // For a plain std::vector-based buffer, "free space" can be interpreted as
    // capacity remaining before reallocation is required.
    if (buffer.capacity() >= buffer.size()) {
        info.free_space = buffer.capacity() - buffer.size();
    } else {
        info.free_space = 0;
    }

    return info;
}
