    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create a read-only adaptor and binary stream over the given buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // --- Preview header without advancing the read pointer ---

    // Peek the first byte (data_type) without consuming it
    // binary_stream supports random access via operator[]
    result.data_type = static_cast<uint8_t>(stream[0]);

    // Check we have enough bytes for at least data_type + item_count
    const std::size_t total_size = buffer.size();
    const std::size_t header_size = sizeof(uint8_t) + sizeof(uint32_t);
    if (total_size < header_size) {
        // Not enough data for even the header; leave result empty
        return result;
    }

    // Read the header properly (this will advance the read pointer)
    uint8_t data_type{};
    uint32_t item_count{};
    stream >> data_type >> item_count;

    // Sanity check: ensure enough bytes remain for the declared number of items
    const std::size_t remaining = total_size - header_size;
    const std::size_t bytes_per_item =
        (data_type == 0) ? sizeof(uint32_t) : sizeof(float);

    if (bytes_per_item == 0 || remaining < bytes_per_item * static_cast<std::size_t>(item_count)) {
        // Not enough data; return header info only
        result.data_type = data_type;
        return result;
    }

    // --- Read items based on data type ---

    if (data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        // Floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    // Store the detected data_type in the result
    result.data_type = data_type;
    return result;
}

