```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create an adaptor over the existing buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw); // avoid exceptions, use state instead

    // Calculate required size: header + container (size + elements)
    std::size_t required_size = sizeof(header);

    // write_container for std::vector typically writes:
    // - size (e.g. as uint64_t or implementation-defined) +
    // - all elements
    //
    // Since we don't know the exact encoding size of the container length
    // in Hexi from the snippets, we conservatively attempt the write using
    // a temporary buffer-adaptor/stream to measure the number of bytes
    // that would be written, then compare against available capacity.

    // First, make sure the underlying buffer is large enough to potentially
    // hold our data; if not, fail early. We only know the exact requirement
    // after doing a dry-run, so we handle capacity via a scratch buffer.

    // Scratch buffer to simulate the write and measure usage
    std::vector<std::uint8_t> scratch;
    scratch.resize(buffer.size()); // same size as the real buffer

    hexi::buffer_adaptor scratch_adaptor(scratch);
    hexi::binary_stream scratch_stream(scratch_adaptor, hexi::no_throw);

    // Simulate the write
    scratch_stream << header;
    scratch_stream.write_container(items);

    if (!scratch_stream) {
        // Even with full buffer size, not enough space
        return false;
    }

    // Number of bytes that would be written
    std::size_t bytes_needed = scratch_adaptor.size();

    // Check if the actual buffer has enough space
    if (bytes_needed > buffer.size()) {
        return false;
    }

    // Now perform the real write into the actual buffer
    stream << header;
    stream.write_container(items);

    return static_cast<bool>(stream);
}
