```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a read-only adaptor and binary_stream over the span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use buffer_adaptor's pointer/read-position methods
    auto* read_ptr   = adaptor.read_ptr();                // current read pointer
    auto  available  = adaptor.read_available();          // bytes available to read

    // Ensure we have enough bytes for the header
    constexpr std::size_t header_size =
        sizeof(std::uint32_t) + sizeof(std::uint16_t) + sizeof(std::uint16_t);
    if (available < header_size || read_ptr == nullptr) {
        return PacketHeader{0, 0, 0};
    }

    // Use binary_stream's zero-copy operation to get a span over the header bytes
    std::span<const std::byte> header_span{};
    stream.view(header_span, header_size); // zero-copy view into underlying buffer

    if (!stream || header_span.size() < header_size) {
        return PacketHeader{0, 0, 0};
    }

    // Interpret the span as raw bytes and manually assemble the header
    // (assumes the buffer uses host endianness; adjust if protocol specifies otherwise)
    const auto* data = reinterpret_cast<const std::uint8_t*>(header_span.data());

    PacketHeader header{};
    std::size_t offset = 0;

    header.magic =
        (static_cast<std::uint32_t>(data[offset + 0])      ) |
        (static_cast<std::uint32_t>(data[offset + 1]) <<  8) |
        (static_cast<std::uint32_t>(data[offset + 2]) << 16) |
        (static_cast<std::uint32_t>(data[offset + 3]) << 24);
    offset += 4;

    header.version =
        (static_cast<std::uint16_t>(data[offset + 0])      ) |
        (static_cast<std::uint16_t>(data[offset + 1]) <<  8);
    offset += 2;

    header.flags =
        (static_cast<std::uint16_t>(data[offset + 0])      ) |
        (static_cast<std::uint16_t>(data[offset + 1]) <<  8);

    return header;
}
