```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Adapt the read-only span into a Hexi buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    MessagePacket packet{};

    // 1. Read the header (uint32_t)
    stream >> packet.header;

    // 2. Get the remaining unread portion of the underlying buffer
    auto remaining = adaptor.read(); // view of data from current read position

    // 3. Interpret remaining data as a char sequence
    std::string_view all_chars{
        reinterpret_cast<const char*>(remaining.data()),
        remaining.size()
    };

    // 4. Find the null terminator
    auto pos = all_chars.find('\0');

    // 5. Create a string_view over the message (excluding the null terminator)
    if (pos != std::string_view::npos) {
        packet.message = all_chars.substr(0, pos);
    } else {
        // If no null is found, treat the entire remaining buffer as the message
        packet.message = all_chars;
    }

    return packet;
}
