```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <cstring>

template<size_t block_size = 1024>
void write_to_dynamic_buffer(hexi::dynamic_buffer<block_size>& buffer,
                             uint32_t header,
                             const std::vector<uint8_t>& data) {
    // Write header as raw bytes (little-endian / native layout)
    buffer.write(&header, sizeof(header));

    // Write data bytes (if any)
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

template<size_t block_size = 1024>
struct BufferData {
    uint32_t header;
    std::vector<uint8_t> data;
};

inline BufferData<> read_from_dynamic_buffer(hexi::dynamic_buffer<1024>& buffer,
                                             size_t data_length) {
    BufferData<> result{};

    // Read header
    buffer.read(&result.header, sizeof(result.header));

    // Read payload
    result.data.resize(data_length);
    if (data_length != 0) {
        buffer.read(result.data.data(), data_length);
    }

    return result;
}
