```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    // The dynamic_buffer API (like the static_buffer in this library) exposes
    // read() / write() offsets and operator[] for indexed access without
    // advancing the read cursor. We can therefore copy directly from the
    // current read offset.

    using size_type = typename hexi::dynamic_buffer<block_size>::size_type;

    const size_type available =
        static_cast<size_type>(buffer.write() - buffer.read());
    const size_type to_copy =
        static_cast<size_type>(std::min<std::size_t>(bytes_to_peek, available));

    std::vector<uint8_t> result;
    result.resize(to_copy);

    const size_type start = buffer.read();
    for (size_type i = 0; i < to_copy; ++i) {
        // Access underlying data without modifying buffer state
        result[i] = static_cast<uint8_t>(buffer[start + i]);
    }

    return result;
}
```

