#include <hexi/allocators/tls_block_allocator.h>
#include <hexi/detail/intrusive_storage.h>
#include <cstdint>

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
using tls_allocator_type =
	hexi::tls_block_allocator<hexi::detail::intrusive_storage<block_size>, allocator_count>;

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void enter_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
	// Ensure the TLS allocator for this thread is created/initialized.
	// The Hexi tls_block_allocator exposes an `allocator()` member that
	// returns a pointer to the per‑thread allocator instance; calling it
	// forces initialization for the current thread.
	//
	// We don't need the return value here; the side effect of setting up
	// the thread-local state is what matters.
	(void)allocator.allocator();
}

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void exit_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
	// Clean up the TLS allocator associated with the current thread.
	// The Hexi tls_block_allocator provides a `reset()` method (or
	// equivalent) to release any per-thread resources and counters.
	//
	// If `allocator()` was never called for this thread, `reset()` is
	// expected to be a no-op.
	allocator.reset();
}
