```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <array>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
//
// This function is intended to be run manually (e.g. from a small sample or test)
// to observe how the free list behaves via the allocator's public counters.
template<std::size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using value_type = std::uint64_t;

    // block_allocator<T, Count>
    // Internally it keeps a pool of Count blocks of sizeof(T)
    // and uses a singly-linked free list; allocate() internally
    // uses pop(), deallocate() uses push().
    hexi::block_allocator<value_type, element_count> alloc;

    std::cout << "Initial state:\n";
    std::cout << "  storage_active_count = " << alloc.storage_active_count << "\n";
    std::cout << "  new_active_count     = " << alloc.new_active_count << "\n";
    std::cout << "  total_allocs         = " << alloc.total_allocs << "\n";
    std::cout << "  total_deallocs       = " << alloc.total_deallocs << "\n\n";

    // Allocate a few blocks and store the pointers so we can
    // deallocate in different orders and observe the effect.
    std::array<value_type*, element_count> ptrs{};
    const std::size_t to_allocate = element_count;

    std::cout << "Allocating " << to_allocate << " blocks:\n";
    for (std::size_t i = 0; i < to_allocate; ++i) {
        ptrs[i] = alloc.allocate();
        *ptrs[i] = static_cast<value_type>(i);

        std::cout << "  allocate() -> ptrs[" << i << "] = " << static_cast<void*>(ptrs[i]) << "\n";
        std::cout << "    storage_active_count = " << alloc.storage_active_count << "\n";
        std::cout << "    new_active_count     = " << alloc.new_active_count << "\n";
        std::cout << "    total_allocs         = " << alloc.total_allocs << "\n";
        std::cout << "    total_deallocs       = " << alloc.total_deallocs << "\n";
    }
    std::cout << "\n";

    // At this point, the internal free list built from the static pool
    // should be exhausted, and any further allocations (if supported by
    // this configuration) would come from "new" and be tracked by
    // new_active_count.

    // Deallocate in a non‑LIFO order to show that the free list is
    // managed as a stack (LIFO). The most recently deallocated element
    // will be at the head of the free list and thus reused first.
    std::cout << "Deallocating in non‑LIFO order (2, 0, 4, 1, 3, ... where valid):\n";
    for (std::size_t i = 0; i < to_allocate; ++i) {
        // simple permutation: even indices first, then odds
        std::size_t idx = (i * 2) % to_allocate;
        std::cout << "  deallocate(ptrs[" << idx << "]) at " << static_cast<void*>(ptrs[idx]) << "\n";
        alloc.deallocate(ptrs[idx]);

        std::cout << "    storage_active_count = " << alloc.storage_active_count << "\n";
