    auto converted = convert_to_big_endian(value);

    // Round trip should return original value
    auto back = convert_from_big_endian(converted);
    EXPECT_EQ(value, back);
}

TEST(Endian, ConvertToLittleEndian) {
    uint32_t value = 0x12345678;
    auto converted = convert_to_little_endian(value);

    // Round trip should return original value
    auto back = convert_from_little_endian(converted);
    EXPECT_EQ(value, back);
}

TEST(Endian, ConvertInt16) {
    int16_t value = 0x1234;
    auto big = convert_to_big_endian(value);
    auto little = convert_to_little_endian(value);

    EXPECT_EQ(value, convert_from_big_endian(big));
    EXPECT_EQ(value, convert_from_little_endian(little));
}

