#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    // Use Hexi's compile-time conditional reverse helper.
    // It already handles integral and floating-point types correctly.
    return hexi::conditional_reverse<from, to>(value);
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    // Fast paths when no conversion is needed
    if (from == to) {
        return value;
    }

    // Dispatch to Hexi's compile-time version when one side matches native
    if (from == std::endian::native && to == std::endian::big) {
        return hexi::native_to_big(value);
    }
    if (from == std::endian::native && to == std::endian::little) {
        return hexi::native_to_little(value);
    }
    if (from == std::endian::big && to == std::endian::native) {
        // Reverse of native_to_big
        return hexi::conditional_reverse<std::endian::big, std::endian::native>(value);
    }
    if (from == std::endian::little && to == std::endian::native) {
        // Reverse of native_to_little
        return hexi::conditional_reverse<std::endian::little, std::endian::native>(value);
    }

    // Remaining cases are big <-> little (or any two non-equal non-native
    // values, but practically that's big <-> little). They are always a swap.
    return hexi::conditional_reverse<std::endian::big, std::endian::little>(value);
}
