    uint32_t value = 0x78563412; // Assume this is big endian representation
    uint32_t original = value;

    convert_from_big_endian_inplace(value);

    // Value should be modified in place
    // Round trip test
    convert_endianness_inplace<std::endian::native, std::endian::big>(value);
    EXPECT_EQ(original, value);
}

TEST(Endian, ConvertFromLittleEndianInplace) {
    uint32_t value = 0x12345678; // Assume this is little endian representation
    uint32_t original = value;

    convert_from_little_endian_inplace(value);

    // Round trip test
    convert_endianness_inplace<std::endian::native, std::endian::little>(value);
    EXPECT_EQ(original, value);
}

TEST(Endian, ConditionalReverseInplace) {
    uint32_t value = 0x12345678;
    uint32_t original = value;

    convert_endianness_inplace<std::endian::native, std::endian::big>(value);
    convert_endianness_inplace<std::endian::big, std::endian::native>(value);

    EXPECT_EQ(original, value);
}

