```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>  // for std::min
#include <cstddef>    // for std::byte
#include <type_traits>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview)
{
    using storage_t = hexi::detail::intrusive_storage<block_size>;
    using value_type = typename storage_t::value_type;

    const size_t readable =
        (storage.write_offset > storage.read_offset)
            ? static_cast<size_t>(storage.write_offset - storage.read_offset)
            : 0;

    const size_t bytes_to_copy = std::min(readable, bytes_to_preview);

    std::vector<uint8_t> result(bytes_to_copy);

    // Pointer to the underlying storage at the current read offset
    const value_type* src = storage.storage.data() + storage.read_offset;

    // Copy depending on underlying value_type
    if constexpr (std::is_same_v<value_type, std::byte>) {
        for (size_t i = 0; i < bytes_to_copy; ++i) {
