#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path,
                                    size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);

    // Determine how many bytes we can actually read
    const auto available = buffer.size();
    const auto to_read   = std::min<std::size_t>(bytes_to_read, available);

    std::vector<std::uint8_t> result(to_read);
    if (to_read > 0) {
        buffer.read(result.data(), to_read);
    }

    return result;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path,
                                       size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);

    const auto available = buffer.size();
    const auto to_preview = std::min<std::size_t>(bytes_to_preview, available);

    std::vector<std::uint8_t> result(to_preview);
    if (to_preview > 0) {
        // Use copy so the read pointer is not advanced
        buffer.copy(result.data(), to_preview);
    }

    return result;
}

void write_file_data(const std::filesystem::path& file_path,
                     const std::vector<uint8_t>& data) {
    // Open file_buffer in write mode; this typically truncates or creates the file.
    hexi::file_buffer buffer(file_path, hexi::file_mode::write);

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
