#include <hexi/file_buffer.h>
#include <hexi/binary_stream.h>
#include <cstdint>
#include <filesystem>

uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    // Open the file through Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str());

    // Wrap it in a binary_stream to use the >> operator for primitive types
    hexi::binary_stream stream(fb);

    std::uint32_t value{};
    stream >> value;  // read uint32_t from the file

    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    // Open the file through Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str());

    // Wrap it in a binary_stream to use the << operator for primitive types
    hexi::binary_stream stream(fb);

    stream << value;  // write uint32_t to the file
}
