```cpp
#include <hexi/file_buffer.h>
#include <filesystem>

size_t get_file_readable_size(const std::filesystem::path& file_path) {
    // Open the file using Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str());

    // If the buffer failed to open or is otherwise invalid, return 0
    if (!fb) {
        return 0;
    }

    // Hexi's file_buffer exposes the remaining readable size via available()
    return fb.available();
}

bool is_file_buffer_valid(const std::filesystem::path& file_path) {
    // Construct a file_buffer; this will attempt to open the file
    hexi::file_buffer fb(file_path.string().c_str());

    // file_buffer is context-convertible to bool to represent error state
    // true  -> buffer is in a good state (no error)
    // false -> an error occurred (e.g., failed to open file)
    return static_cast<bool>(fb);
}
```

