```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <cstdio>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path,
                                         size_t header_size) {
    // Open file using C stdio, since hexi::file_buffer wraps a FILE*
    FILE* f = std::fopen(file_path.string().c_str(), "rb");
    if (!f || header_size == 0) {
        if (f) {
            std::fclose(f);
        }
        return {};
    }

    // Determine how many bytes are actually available from the start
    if (std::fseek(f, 0, SEEK_END) != 0) {
        std::fclose(f);
        return {};
    }
    long file_size = std::ftell(f);
    if (file_size < 0) {
        std::fclose(f);
        return {};
    }

    // Clamp requested header size to file size
    const size_t bytes_to_read =
        header_size > static_cast<size_t>(file_size)
            ? static_cast<size_t>(file_size)
            : header_size;

    // Read from the beginning without leaving the file positioned ahead
    if (std::fseek(f, 0, SEEK_SET) != 0) {
        std::fclose(f);
        return {};
    }

    std::vector<uint8_t> header(bytes_to_read);
    if (bytes_to_read > 0) {
        const size_t read_count = std::fread(header.data(), 1, bytes_to_read, f);
        header.resize(read_count); // in case of short read
    }

    std::fclose(f);
    return header;
}
