```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>

template<std::size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                          const std::vector<std::uint8_t>& data) {
    if (data.empty()) {
        return;
    }

    // Write as many bytes as will fit from the current write position.
    const std::size_t writable =
        std::min<std::size_t>(data.size(), buffer_size - buffer.write_position());

    if (writable == 0) {
        return; // no space left
    }

    // static_buffer stores std::byte, but our input is uint8_t.
    // Copy element-wise, converting each uint8_t to std::byte.
    for (std::size_t i = 0; i < writable; ++i) {
        std::byte b = static_cast<std::byte>(data[i]);
        buffer.write(&b, 1);
    }
}

template<std::size_t buffer_size = 1024>
std::vector<std::uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                                                std::size_t bytes_to_read) {
    std::vector<std::uint8_t> result;
    if (bytes_to_read == 0) {
        return result;
    }

    // Only read as much as is currently available.
    const std::size_t readable =
        std::min<std::size_t>(bytes_to_read, buffer.size());

    result.resize(readable);
    for (std::size_t i = 0; i < readable; ++i) {
        std::byte b{};
        buffer.read(&b, 1);
        result[i] = static_cast<std::uint8_t>(b);
    }

    return result;
}
