output.text:
```cpp
#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;     // total buffer capacity
    size_t current_size; // currently readable data
    size_t free_space;   // remaining writable space
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info{};

    // Total capacity comes from the static_buffer's size()
    info.capacity = buffer.size();

    // Current readable data is how much is available to read
    info.current_size = buffer.readable_size();

    // Free space is the difference between capacity and current size
    info.free_space = info.capacity - info.current_size;

    return info;
}
```

