```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer,
                                         size_t bytes_to_preview) {
    // The static_buffer API (from hexi) exposes read-only access via the
    // buffer_read interface, typically through operator[] and size().
    //
    // Because we take the buffer by const reference, we can safely index
    // into it without advancing the internal read pointer. We simply copy
    // up to bytes_to_preview bytes (clamped by buffer.size()) into a
    // std::vector<uint8_t> and return it.

    const std::size_t available = buffer.size();
    const std::size_t to_copy   = std::min<std::size_t>(available, bytes_to_preview);

    std::vector<uint8_t> result;
    result.reserve(to_copy);

    for (std::size_t i = 0; i < to_copy; ++i) {
        // buffer[i] returns a std::byte; convert it to uint8_t
        std::byte b = buffer[i];
        result.push_back(static_cast<std::uint8_t>(b));
    }

    return result;
}
```

