    MockBuffer buffer;
    hexi::pmc::stream_base stream(buffer);

    bool is_good = is_stream_good(stream);

    EXPECT_TRUE(is_good);
}

TEST(StreamBase, CheckStateAfterError) {
    MockBuffer buffer;
    hexi::pmc::stream_base stream(buffer);

    stream.set_error_state();

    auto state = get_stream_state(stream);
    bool is_good = is_stream_good(stream);

    EXPECT_EQ(hexi::stream_state::user_defined_err, state);
    EXPECT_FALSE(is_good);
}

