```cpp
#include <hexi/pmc/stream_base.h>
#include <hexi/shared.h>

size_t get_stream_size(const hexi::pmc::stream_base& stream) {
    // stream_base holds a reference to a buffer_base, which (via buffer_read)
    // exposes size() as the size of the underlying buffer.
    //
    // buffer_base provides a const buffer_read& view through which size() can
    // be queried. In the actual Hexi implementation this is accessible via
    // a virtual size() function on buffer_base/buffer_read.
    //
    // Here we simply delegate to that interface.
    return stream.buffer().size();
}

bool is_stream_empty(const hexi::pmc::stream_base& stream) {
    // A stream is considered empty if its underlying buffer has size 0.
    return get_stream_size(stream) == 0;
}

struct StreamInfo {
    hexi::stream_state state;
    size_t buffer_size;
    bool is_empty;
};

StreamInfo get_stream_state_info(const hexi::pmc::stream_base& stream) {
    StreamInfo info{};
    info.state       = stream.state();
    info.buffer_size = get_stream_size(stream);
    info.is_empty    = (info.buffer_size == 0);
    return info;
}
