#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write length as a 32-bit unsigned integer, then the raw bytes
    std::uint32_t len = static_cast<std::uint32_t>(str.size());
    writer.write(len);
    if (len > 0) {
        writer.write_bytes(str.data(), len);
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read length then that many bytes into a std::string
    std::uint32_t len = 0;
    reader.read(len);

    std::string result;
    result.resize(len);

    if (len > 0) {
        reader.read_bytes(result.data(), len);
    }

    return result;
}
