output.text:
```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstddef>

void write_data_to_buffer(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::uint32_t value,
    const void* data,
    std::size_t length
) {
    // Reserve enough space for the integer and the byte array
    buffer.reserve(sizeof(std::uint32_t) + length);

    // Write the 32-bit integer value
    buffer.write(&value, sizeof(std::uint32_t));

    // Write the raw data bytes
    if (data != nullptr && length > 0) {
        buffer.write(data, length);
    }
}

void read_data_from_buffer(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::uint32_t& value,
    void* data,
    std::size_t length
) {
    // Read the 32-bit integer value
    buffer.read(&value, sizeof(std::uint32_t));

    // Read the raw data bytes
    if (data != nullptr && length > 0) {
        buffer.read(data, length);
    }
}

struct BufferInfo {
    std::size_t size;
    std::size_t free_space;
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info{};
    info.size = buffer.size();

    // For a std::vector-backed adaptor, capacity() - size() is a reasonable
    // interpretation of "free space" in the underlying container.
    auto& underlying = buffer.get();
    info.free_space = underlying.capacity() > underlying.size()
        ? (underlying.capacity() - underlying.size())
        : 0;

    return info;
}
