#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcmp

// Copy raw bytes from the buffer without advancing the read pointer
void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           void* data,
                           std::size_t length) {
    // Use the non-template copy() overload: (void* destination, std::size_t length) const
    buffer.copy(data, length);
}

// Copy a single value of type T from the buffer without advancing the read pointer
template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, T& value) {
    // Use the template copy<T>() overload to copy a single value
    buffer.copy(value);
}

// Peek at data in the buffer and compare it with expected data without consuming it
bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                      const void* expected,
                      std::size_t length) {
    if (length == 0) {
        return true;
    }

    std::vector<std::byte> tmp(length);
    // Peek data into temporary buffer
    buffer.copy(tmp.data(), length);

    // Compare with expected
    return std::memcmp(tmp.data(), expected, length) == 0;
}
