```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read.h>
#include <vector>
#include <cstdint>
#include <cstddef>   // for std::size_t
#include <algorithm> // for std::find

std::size_t find_byte_in_buffer(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value)
{
    using hexi::pmc::buffer_read;

    // Get a raw pointer to the readable bytes and the current size
    const std::byte* data = buffer.data();
    const std::size_t sz  = buffer.size();

    // Use std::find over the contiguous range
    const std::byte* it = std::find(data, data + sz, value);

    if (it == data + sz) {
        return buffer_read::npos;
    }

    return static_cast<std::size_t>(it - data);
}

std::size_t find_delimiter_position(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte delimiter)
{
    // Just reuse the generic byte-finding function
    return find_byte_in_buffer(buffer, delimiter);
}

bool check_buffer_contains(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value)
{
    using hexi::pmc::buffer_read;

    const std::size_t pos = find_byte_in_buffer(buffer, value);
    return pos != buffer_read::npos;
}
