```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          std::size_t bytes) {
    // buffer_adaptor exposes the generic buffer interface which, via buffer_read,
    // provides a skip function that advances the read position without copying.
    buffer.skip(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header{};

    // Read the message_type (2 bytes)
    {
        std::byte tmp[sizeof(header.message_type)];
        buffer.read(tmp, sizeof(tmp));
        std::memcpy(&header.message_type, tmp, sizeof(header.message_type));
    }

    // Read the body_length (4 bytes)
    {
        std::byte tmp[sizeof(header.body_length)];
        buffer.read(tmp, sizeof(tmp));
        std::memcpy(&header.body_length, tmp, sizeof(header.body_length));
    }

    // Skip the body using the length from the header
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
