#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

// Standard unsigned LEB128-style varint encoding for integral types.
// For signed types, this treats the value as its unsigned representation
// (i.e., no ZigZag); encoder/decoder must use the same T.

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_integral_v<T>, "encode_varint requires integral type");

    using UnsignedT = std::make_unsigned_t<T>;
    UnsignedT v = static_cast<UnsignedT>(value);

    std::size_t bytes_written = 0;
    std::uint8_t byte = 0;

    do {
        byte = static_cast<std::uint8_t>(v & 0x7F);
        v >>= 7;
        if (v != 0) {
            byte |= 0x80; // continuation bit
        }
        writer.write(byte);
        ++bytes_written;
    } while (v != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_integral_v<T>, "decode_varint requires integral type");

    using UnsignedT = std::make_unsigned_t<T>;
    UnsignedT result = 0;
    std::size_t shift = 0;

    // Maximum number of bytes a varint for this type can occupy
    constexpr std::size_t max_bytes =
        (sizeof(T) * 8 + 6) / 7; // ceil(bits/7)

    for (std::size_t i = 0; i < max_bytes; ++i) {
        std::uint8_t byte = 0;
        reader.read(byte);

        UnsignedT chunk = static_cast<UnsignedT>(byte & 0x7F);
        result |= (chunk << shift);

        if ((byte & 0x80) == 0) {
            // Last byte
            return static_cast<T>(result);
        }

        shift += 7;
    }

    // If we get here, the varint is too long for T; behavior in this case
    // is left as-is: we just return what we accumulated.
    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    static_assert(std::is_integral_v<T>, "encode_decode_roundtrip requires integral type");

    std::vector<std::byte> buffer_storage;
    hexi::pmc::buffer_adaptor adaptor(buffer_storage);

    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    encode_varint(writer, original_value);
    T decoded = decode_varint<T>(reader);

    return decoded == original_value;
}
