#include <hexi/hexi.h>
#include <string>
#include <string_view>

void write_string_prefixed_varint(hexi::binary_stream& stream, const std::string& str) {
    // Use the Hexi prefixed_varint adaptor with the stream's operator<<
    stream << hexi::prefixed_varint(str);
}

std::string read_string_prefixed_varint(hexi::binary_stream& stream) {
    // Read into a std::string using the prefixed_varint adaptor
    std::string result;
    std::string_view view;

    // Read into a string_view first; Hexi will manage the underlying buffer
    stream >> hexi::prefixed_varint(view);

    // Copy the data out into a standalone std::string to return
    result.assign(view.begin(), view.end());
    return result;
}

