```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Treat null pointers with non‑zero length as invalid / overlapping for safety
    if ((!src && src_len != 0) || (!dst && dst_len != 0)) {
        return true;
    }

    // Zero-length regions never overlap
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    const auto src_begin = static_cast<const std::byte*>(src);
    const auto dst_begin = static_cast<const std::byte*>(dst);

    const auto src_end = src_begin + src_len;
    const auto dst_end = dst_begin + dst_len;

    // Two ranges [a,b) and [c,d) overlap iff a < d && c < b
    return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Null checks: if length is non-zero and either pointer is null,
    // we treat as failure (and thus "not safe").
    if (length != 0 && (!destination || !source)) {
        return false;
    }

    if (check_regions_overlap(source, length, destination, length)) {
        // Overlapping regions: copying is not considered safe here
        return false;
    }

    // Non-overlapping: safe to use memcpy
    std::memcpy(destination, source, length);
    return true;
}
