struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info{0, 0, 0, false};

    // Create a small buffer and stream with a strict read limit,
    // then intentionally read past the limit to trigger the exception.
    std::array<std::uint8_t, 8> buffer{};
    hexi::pmc::buffer_adaptor adaptor(buffer);
    // Set a read limit smaller than what we'll attempt to read.
    hexi::pmc::binary_stream stream(adaptor, 4);

    try {
        // Attempt to read more than the limit to force stream_read_limit
        std::uint8_t temp[8];
        stream.read(temp, sizeof(temp));
    } catch (const hexi::stream_read_limit& ex) {
        info.read_size  = ex.read_size();
        info.total_read = ex.total_read();
        info.read_limit = ex.read_limit();
        info.occurred   = true;
    } catch (...) {
        // Any other exception type: just report that no stream_read_limit occurred.
        info.occurred = false;
    }

    return info;
}

