    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Backing buffer for output
    std::vector<std::uint8_t> buffer;

    // Create a buffer adaptor over the vector and a binary_stream for writing
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write packet_id as a plain 32-bit integer
    stream(packet.packet_id);

    // Use prefixed_varint adaptor for compact encoding of the tags vector.
    // The adaptor will encode the size of the vector, as well as the size
    // of each string, using variable-length integers.
    auto tags_compact = hexi::prefixed_varint(packet.tags);
    stream(tags_compact);

    // Use prefixed_varint adaptor for compact encoding of the data string
    auto data_compact = hexi::prefixed_varint(packet.data);
    stream(data_compact);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet{};

    // Create a read-only adaptor over the input span and a binary_stream for reading
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream(packet.packet_id);

    // Read tags vector using prefixed_varint adaptor
    auto tags_compact = hexi::prefixed_varint(packet.tags);
    stream(tags_compact);

    // Read data string using prefixed_varint adaptor
    auto data_compact = hexi::prefixed_varint(packet.data);
    stream(data_compact);

    return packet;
}
