#include <hexi/hexi.h>
#include <string>
#include <cstdint>
#include <vector>

struct PaddedData {
    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Backing buffer
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor and binary stream over our std::vector<uint8_t>
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write header
    stream << packet.header;

    // Write data with a length prefix.
    // Hexi's binary_stream knows how to serialize std::string with a length prefix
    // (consistent with the rest of the repo examples).
    stream << packet.data;

    // Write exactly 16 bytes of 0x00 padding
    stream.fill<16>(0x00);

    // Write footer
    stream << packet.footer;

    return buffer;
}
```

