```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstring>   // for std::memcpy

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Backing storage for the adaptors
    std::vector<std::uint8_t> buffer;

    // Create a write adaptor over the buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // Ensure there is enough free space before writing
    if (write_adaptor.free() < input_data.size()) {
        // Grow the underlying buffer to have at least input_data.size() free bytes.
        // Typically you'd grow by the difference between needed and free.
        const std::size_t additional = input_data.size() - write_adaptor.free();
        buffer.resize(buffer.size() + additional);
    }

    // Write the input data into the buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Now create a read adaptor over the same buffer to read data back
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Check how much data is readable
    const std::size_t readable = read_adaptor.size();
    std::vector<std::uint8_t> output(readable);

    // Read all available data
    if (readable != 0) {
        read_adaptor.read(output.data(), readable);
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create a read adaptor over the provided buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data);

    // Do not attempt to peek more than is available
    const std::size_t available = read_adaptor.size();
    const std::size_t to_peek = std::min(peek_size, available);

    std::vector<std::uint8_t> peeked(to_peek);

    if (to_peek == 0) {
        return peeked;
    }

    // Get pointer to current read position
    const std::uint8_t* ptr = static_cast<const std::uint8_t*>(read_adaptor.read_ptr());

    // Use copy() to peek at data without advancing read position
    // (depending on the exact Hexi API, copy() may take (void*, size_t) or similar)
    read_adaptor.copy(peeked.data(), to_peek);

    // Alternatively, if copy() is not used directly, use ptr as the source:
    // std::memcpy(peeked.data(), ptr, to_peek);

    // Now actually consume the same data with read()
    std::vector<std::uint8_t> consumed(to_peek);
    read_adaptor.read(consumed.data(), to_peek);

    // Return the peeked data (what we observed without moving the cursor initially)
    return peeked;
}
