```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// Writes the given chunks into a pmc write buffer, using free() before each write.
// Returns the final size (amount of data stored in the buffer).
std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Choose some capacity large enough to demonstrate multiple writes.
    // In a real setting this might be parameterised or inferred.
    constexpr std::size_t kCapacity = 1024;

    hexi::pmc::buffer_write_adaptor adaptor(kCapacity);

    for (const auto& chunk : chunks) {
        const std::uint8_t* data = chunk.data();
        std::size_t remaining = chunk.size();

        // We may need multiple writes per chunk if it is larger than the remaining free space.
        while (remaining > 0 && adaptor.free() > 0) {
            const std::size_t writable = std::min<std::size_t>(remaining, adaptor.free());
            adaptor.write(data, writable);
            data += writable;
            remaining -= writable;
        }

        // If remaining > 0 here, the buffer is full and we stop.
        if (remaining > 0) {
            break;
        }
    }

    // size() reports how many bytes have been written into the buffer.
    return adaptor.size();
}

// Reads data from a pmc read buffer in partial chunks of size `chunk_size`.
// Uses size() after each read to track remaining bytes and continues until empty.
// Returns all read bytes concatenated into a single vector.
std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    std::vector<std::uint8_t> result;
    result.reserve(buffer.size());

    while (adaptor.size() > 0) {
        const std::size_t to_read = std::min<std::size_t>(chunk_size, adaptor.size());
        std::vector<std::uint8_t> tmp(to_read);

        adaptor.read(tmp.data(), to_read);
        // After this read, adaptor.size() reflects remaining data.

        result.insert(result.end(), tmp.begin(), tmp.end());
    }

    return result;
}
