#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read adaptor over the const buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header{};

    // Peek at the header bytes without consuming them
    // copy() reads from the current read position but does not advance it
    adaptor.copy(&header, sizeof(Header));

    // Verify the pointer to the current read position; it should still
    // point at the first byte, because copy() does not advance the cursor
    const std::byte* ptr = adaptor.read_ptr();

    // Optional: basic sanity check that the pointer corresponds to buffer[0]
    // (only if the buffer is large enough). This does not change state.
    if (!buffer.empty()) {
        const uint8_t* raw = reinterpret_cast<const uint8_t*>(ptr);
        (void)raw; // suppress unused-variable warning in case this isn't used
    }

    // Return the peeked header; the adaptor's read position is unchanged
    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);
    std::vector<uint8_t> result;

    if (buffer.empty()) {
        return result;
    }

    // Peek at the first byte without consuming it
    uint8_t first = 0;
    adaptor.copy(&first, sizeof(first));

    // Example condition: if the first byte is non-zero, consume and return
    // the rest of the buffer; otherwise, consume nothing and return empty.
    if (first != 0) {
        // Now actually consume the data using read()
        // First consume the byte we already peeked
        uint8_t consumed_first = 0;
        adaptor.read(&consumed_first, sizeof(consumed_first));

        // Then consume the remaining bytes
        const std::size_t remaining = buffer.size() - 1;
        result.resize(1 + remaining);
        result[0] = consumed_first;

        if (remaining > 0) {
            adaptor.read(result.data() + 1, remaining);
        }
    }

    return result;
}
