        stream.write(be_message_id);
    }

    // Convert and write data_values (std::vector<uint16_t>) as big-endian
    {
        std::vector<uint16_t> be_values;
        be_values.reserve(packet.data_values.size());
        for (uint16_t v : packet.data_values) {
            be_values.push_back(endian::native_to_big(v));
        }

        // The method write_container writes the container elements as-is, so we
        // pass the already big-endian converted vector.
        stream.write_container(be_values);
    }

    // Convert and write checksum (uint32_t) as big-endian
    {
        uint32_t be_checksum = endian::native_to_big(packet.checksum);
        stream.write(be_checksum);
    }

